import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import Header from '../../components/layout/Header';
import Footer from '../../components/layout/Footer';
import { useCart } from '../../context/CartContext';
import { useAuth } from '../../context/AuthContext';
import './CheckoutPage.css';

const MEMBERSHIP_FEE = 499;
const BORROW_FEE_PER_BOOK = 0; // Free borrow, membership only

export default function CheckoutPage() {
  const { items, clearCart } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();

  const [step, setStep] = useState(1); // 1=address, 2=payment, 3=success
  const [payMethod, setPayMethod] = useState('card');
  const [processing, setProcessing] = useState(false);

  const [address, setAddress] = useState({
    fullName: user?.name || '',
    phone: user?.phone || '',
    street: '',
    city: 'Surat',
    state: 'Gujarat',
    pincode: '',
  });

  const [card, setCard] = useState({
    number: '',
    name: '',
    expiry: '',
    cvv: '',
  });

  const [upi, setUpi] = useState('');

  const totalFee = MEMBERSHIP_FEE;

  const formatCard = (val) => {
    return val.replace(/\D/g, '').replace(/(.{4})/g, '$1 ').trim().slice(0, 19);
  };

  const formatExpiry = (val) => {
    return val.replace(/\D/g, '').replace(/(\d{2})(\d)/, '$1/$2').slice(0, 5);
  };

  const handleAddressNext = (e) => {
    e.preventDefault();
    if (!address.street || !address.pincode) {
      toast.error('Please fill all address fields');
      return;
    }
    setStep(2);
    window.scrollTo(0, 0);
  };

  const handlePayment = async (e) => {
    e.preventDefault();
    setProcessing(true);

    // Simulate payment processing
    await new Promise(r => setTimeout(r, 2500));

    setProcessing(false);
    setStep(3);
    clearCart();
    window.scrollTo(0, 0);
  };

  if (items.length === 0 && step !== 3) {
    return (
      <div className="checkout-page">
        <Header />
        <div style={{ minHeight: '80vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 20 }}>
          <div style={{ fontSize: 64 }}>🛒</div>
          <h2 style={{ fontFamily: 'Cormorant Garamond, serif', fontSize: 32, fontWeight: 300, color: 'var(--text-primary)' }}>Cart is Empty</h2>
          <Link to="/collection" className="chk-btn-primary">Browse Collection</Link>
        </div>
        <Footer />
      </div>
    );
  }

  return (
    <div className="checkout-page">
      <Header />

      <section className="chk-hero">
        <div className="chk-hero__bg" />
        <div className="container chk-hero__inner">
          <p className="chk-tag"><span className="chk-tag-line" />Checkout</p>
          <h1 className="chk-title">
            {step === 1 ? 'Delivery Details' : step === 2 ? 'Payment' : 'Order Confirmed!'}
          </h1>
        </div>
      </section>

      {/* Progress Bar */}
      {step < 3 && (
        <div className="chk-progress">
          <div className="container">
            <div className="chk-steps">
              {['Cart', 'Address', 'Payment', 'Done'].map((s, i) => (
                <div key={i} className={`chk-step ${i + 1 <= step + 1 ? 'active' : ''} ${i + 1 < step ? 'done' : ''}`}>
                  <div className="chk-step__dot">{i + 1 < step ? '✓' : i + 1}</div>
                  <span className="chk-step__label">{s}</span>
                  {i < 3 && <div className="chk-step__line" />}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <section className="chk-body">
        <div className="container">

          {/* ── STEP 1: ADDRESS ── */}
          {step === 1 && (
            <div className="chk-grid">
              <div className="chk-main">
                <div className="chk-card">
                  <h2 className="chk-card__title">📍 Delivery / Contact Address</h2>
                  <p className="chk-card__subtitle">We'll send your membership details to this address.</p>
                  <form onSubmit={handleAddressNext} className="chk-form">
                    <div className="chk-form-row">
                      <div className="chk-form-group">
                        <label>Full Name *</label>
                        <input value={address.fullName} onChange={e => setAddress(p => ({...p, fullName: e.target.value}))} required placeholder="Your full name" />
                      </div>
                      <div className="chk-form-group">
                        <label>Phone *</label>
                        <input value={address.phone} onChange={e => setAddress(p => ({...p, phone: e.target.value}))} required placeholder="+91 98765 43210" />
                      </div>
                    </div>
                    <div className="chk-form-group">
                      <label>Street Address *</label>
                      <input value={address.street} onChange={e => setAddress(p => ({...p, street: e.target.value}))} required placeholder="House no., Street, Area" />
                    </div>
                    <div className="chk-form-row">
                      <div className="chk-form-group">
                        <label>City *</label>
                        <input value={address.city} onChange={e => setAddress(p => ({...p, city: e.target.value}))} required />
                      </div>
                      <div className="chk-form-group">
                        <label>State *</label>
                        <input value={address.state} onChange={e => setAddress(p => ({...p, state: e.target.value}))} required />
                      </div>
                      <div className="chk-form-group">
                        <label>PIN Code *</label>
                        <input value={address.pincode} onChange={e => setAddress(p => ({...p, pincode: e.target.value.replace(/\D/,'').slice(0,6)}))} required placeholder="395010" maxLength={6} />
                      </div>
                    </div>
                    <button type="submit" className="chk-btn-primary">Continue to Payment →</button>
                  </form>
                </div>
              </div>
              <OrderSummary items={items} totalFee={totalFee} />
            </div>
          )}

          {/* ── STEP 2: PAYMENT ── */}
          {step === 2 && (
            <div className="chk-grid">
              <div className="chk-main">
                <div className="chk-card">
                  <h2 className="chk-card__title">💳 Choose Payment Method</h2>

                  {/* Payment Method Tabs */}
                  <div className="pay-tabs">
                    {[
                      { id: 'card', icon: '💳', label: 'Credit / Debit Card' },
                      { id: 'upi',  icon: '📱', label: 'UPI' },
                      { id: 'cash', icon: '💵', label: 'Cash at Library' },
                    ].map(m => (
                      <button
                        key={m.id}
                        className={`pay-tab ${payMethod === m.id ? 'active' : ''}`}
                        onClick={() => setPayMethod(m.id)}
                        type="button"
                      >
                        <span className="pay-tab__icon">{m.icon}</span>
                        <span className="pay-tab__label">{m.label}</span>
                        {payMethod === m.id && <span className="pay-tab__check">✓</span>}
                      </button>
                    ))}
                  </div>

                  <form onSubmit={handlePayment} className="chk-form" style={{ marginTop: 28 }}>

                    {/* Card Payment */}
                    {payMethod === 'card' && (
                      <div className="pay-card-form">
                        {/* Card Preview */}
                        <div className="card-preview">
                          <div className="card-preview__chip">◼</div>
                          <div className="card-preview__number">
                            {card.number || '•••• •••• •••• ••••'}
                          </div>
                          <div className="card-preview__bottom">
                            <div>
                              <div className="card-preview__label">Card Holder</div>
                              <div className="card-preview__value">{card.name || 'YOUR NAME'}</div>
                            </div>
                            <div>
                              <div className="card-preview__label">Expires</div>
                              <div className="card-preview__value">{card.expiry || 'MM/YY'}</div>
                            </div>
                          </div>
                        </div>

                        <div className="chk-form-group">
                          <label>Card Number *</label>
                          <input
                            value={card.number}
                            onChange={e => setCard(p => ({...p, number: formatCard(e.target.value)}))}
                            placeholder="1234 5678 9012 3456"
                            required maxLength={19}
                          />
                        </div>
                        <div className="chk-form-group">
                          <label>Cardholder Name *</label>
                          <input
                            value={card.name}
                            onChange={e => setCard(p => ({...p, name: e.target.value.toUpperCase()}))}
                            placeholder="AS ON CARD"
                            required
                          />
                        </div>
                        <div className="chk-form-row">
                          <div className="chk-form-group">
                            <label>Expiry Date *</label>
                            <input
                              value={card.expiry}
                              onChange={e => setCard(p => ({...p, expiry: formatExpiry(e.target.value)}))}
                              placeholder="MM/YY"
                              required maxLength={5}
                            />
                          </div>
                          <div className="chk-form-group">
                            <label>CVV *</label>
                            <input
                              value={card.cvv}
                              onChange={e => setCard(p => ({...p, cvv: e.target.value.replace(/\D/,'').slice(0,4)}))}
                              placeholder="•••"
                              type="password"
                              required maxLength={4}
                            />
                          </div>
                        </div>

                        {/* Accepted Cards */}
                        <div className="card-logos">
                          <span>VISA</span><span>Mastercard</span><span>RuPay</span><span>Amex</span>
                        </div>
                      </div>
                    )}

                    {/* UPI Payment */}
                    {payMethod === 'upi' && (
                      <div>
                        <div className="upi-logos">
                          {['GPay', 'PhonePe', 'Paytm', 'BHIM'].map(u => (
                            <div key={u} className="upi-logo">{u}</div>
                          ))}
                        </div>
                        <div className="chk-form-group" style={{ marginTop: 20 }}>
                          <label>UPI ID *</label>
                          <input
                            value={upi}
                            onChange={e => setUpi(e.target.value)}
                            placeholder="yourname@upi"
                            required
                          />
                        </div>
                        <div className="upi-note">
                          💡 Enter your UPI ID — a payment request will be sent to your UPI app
                        </div>
                      </div>
                    )}

                    {/* Cash Payment */}
                    {payMethod === 'cash' && (
                      <div className="cash-info">
                        <div className="cash-info__icon">💵</div>
                        <h3>Pay at Library</h3>
                        <p>Visit Luxe Library at Atmanand Saraswati Science College, Kapodara, Surat and pay ₹{totalFee} at the front desk.</p>
                        <div className="cash-info__details">
                          <div><span>📍</span> Kapodara, Surat — 395010</div>
                          <div><span>📞</span> +91 96246 07410</div>
                          <div><span>🕐</span> Mon–Sat: 9AM – 8PM</div>
                        </div>
                      </div>
                    )}

                    <div className="chk-secure">
                      🔒 100% Secure Payment — SSL Encrypted
                    </div>

                    <div style={{ display: 'flex', gap: 12, marginTop: 8 }}>
                      <button type="button" className="chk-btn-ghost" onClick={() => setStep(1)}>← Back</button>
                      <button type="submit" className="chk-btn-primary" disabled={processing} style={{ flex: 1 }}>
                        {processing ? (
                          <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10 }}>
                            <span className="chk-spinner" /> Processing Payment...
                          </span>
                        ) : `Pay ₹${totalFee} →`}
                      </button>
                    </div>
                  </form>
                </div>
              </div>
              <OrderSummary items={items} totalFee={totalFee} showAddress address={address} />
            </div>
          )}

          {/* ── STEP 3: SUCCESS ── */}
          {step === 3 && (
            <div className="chk-success">
              <div className="chk-success__circle">
                <span className="chk-success__check">✓</span>
              </div>
              <h2 className="chk-success__title">Payment Successful!</h2>
              <p className="chk-success__subtitle">
                Your membership has been confirmed. Please visit the library with your Member ID to collect your books.
              </p>
              <div className="chk-success__card">
                <div className="chk-success__row"><span>Member Name</span><strong>{address.fullName}</strong></div>
                <div className="chk-success__row"><span>Member ID</span><strong style={{ color: 'var(--gold)' }}>{user?.membershipId || 'LIB00001'}</strong></div>
                <div className="chk-success__row"><span>Amount Paid</span><strong>₹{totalFee}</strong></div>
                <div className="chk-success__row"><span>Payment Method</span><strong style={{ textTransform: 'capitalize' }}>{payMethod}</strong></div>
                <div className="chk-success__row"><span>Status</span><strong style={{ color: 'var(--green)' }}>✅ Confirmed</strong></div>
              </div>
              <div className="chk-success__actions">
                <Link to="/dashboard" className="chk-btn-primary">Go to Dashboard</Link>
                <Link to="/collection" className="chk-btn-ghost">Browse More Books</Link>
              </div>
              <div className="chk-success__visit">
                <span>📍</span>
                <span>Visit: Atmanand Saraswati Science College, Kapodara, Surat — 395010 &nbsp;|&nbsp; 📞 +91 96246 07410</span>
              </div>
            </div>
          )}

        </div>
      </section>

      <Footer />
    </div>
  );
}

function OrderSummary({ items, totalFee, showAddress, address }) {
  return (
    <div className="chk-summary">
      <div className="chk-summary__box">
        <h3 className="chk-summary__title">Order Summary</h3>

        {/* Books */}
        <div className="chk-summary__books">
          {items.map(b => (
            <div key={b._id} className="chk-summary__book">
              <div className="chk-summary__book-cover">
                {b.coverImage
                  ? <img src={b.coverImage} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                  : <span>📖</span>
                }
              </div>
              <div className="chk-summary__book-info">
                <div className="chk-summary__book-title">{b.title}</div>
                <div className="chk-summary__book-author">by {b.author}</div>
              </div>
            </div>
          ))}
        </div>

        <div className="chk-summary__divider" />

        <div className="chk-summary__row">
          <span>Books Selected</span>
          <span>{items.length}</span>
        </div>
        <div className="chk-summary__row">
          <span>Membership Fee</span>
          <span>₹{totalFee}</span>
        </div>
        <div className="chk-summary__row chk-summary__total">
          <span>Total</span>
          <span>₹{totalFee}</span>
        </div>

        {showAddress && address?.street && (
          <>
            <div className="chk-summary__divider" />
            <div className="chk-summary__address">
              <div className="chk-summary__addr-title">📍 Deliver To</div>
              <div className="chk-summary__addr-text">
                {address.fullName}<br />
                {address.street}<br />
                {address.city}, {address.state} — {address.pincode}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
